function sha256(data) {
  return createHash('sha256').update(data).digest('hex');
}

function canonicalText(data) {
  let text = Buffer.isBuffer(data) ? data.toString('utf8') : String(data);
  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
  return text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function canonicalSha(data) {
  return sha256(Buffer.from(canonicalText(data), 'utf8'));
}

function fileBuffer(root, relativePath) {
  return readFileSync(join(root, relativePath));
}

function fileSha(root, relativePath) {
  return sha256(fileBuffer(root, relativePath));
}

function fileCanonicalSha(root, relativePath) {
  return canonicalSha(fileBuffer(root, relativePath));
}

function entryAfterBuffer(entry) {
  const body = Buffer.from(entry.content, 'utf8');
  return entry.hadBom
    ? Buffer.concat([Buffer.from([0xef, 0xbb, 0xbf]), body])
    : body;
}

function entryAfterCanonicalSha(entry) {
  return canonicalSha(entryAfterBuffer(entry));
}

function detectTextFormat(buffer) {
  const hasBom = buffer.length >= 3 && buffer[0] === 0xef && buffer[1] === 0xbb && buffer[2] === 0xbf;
  const text = buffer.toString('utf8');
  const crlf = (text.match(/\r\n/g) || []).length;
  const bareLf = (text.match(/(?<!\r)\n/g) || []).length;
  const bareCr = (text.match(/\r(?!\n)/g) || []).length;
  const eol = crlf && !bareLf && !bareCr ? 'CRLF' : bareLf && !crlf && !bareCr ? 'LF' : crlf || bareLf || bareCr ? 'mixed' : 'none';
  return `${eol}${hasBom ? '+BOM' : ''}`;
}

function timestamp() {
  return new Date().toISOString().replace(/[:.]/g, '-');
}

function findProjectRootFrom(start) {
  let current = resolve(start);
  for (let depth = 0; depth < 8; depth += 1) {
    if (
      existsSync(join(current, 'package.json')) &&
      existsSync(join(current, 'client', 'src', 'GameScene.ts')) &&
      existsSync(join(current, 'server', 'src', 'rooms', 'Drop8Room.ts')) &&
      existsSync(join(current, 'shared', 'src', 'index.ts'))
    ) return current;
    const parent = resolve(current, '..');
    if (parent === current) break;
    current = parent;
  }
  return null;
}

function findProjectRoot() {
  const scriptPath = process.argv[1] ? resolve(process.argv[1]) : process.cwd();
  for (const candidate of [process.cwd(), dirname(scriptPath)]) {
    const found = findProjectRootFrom(candidate);
    if (found) return found;
  }
  throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. package.json과 client/server/shared 폴더가 있는 최상위 폴더에서 실행하세요.');
}

function uniqueBackupDir(root) {
  const base = join(root, 'patch_backups', BACKUP_BASENAME);
  if (!existsSync(base)) return base;
  let candidate = `${base}_${timestamp()}`;
  let suffix = 2;
  while (existsSync(candidate)) candidate = `${base}_${timestamp()}_${suffix++}`;
  return candidate;
}

function windowsQuote(value) {
  const text = String(value);
  if (/^[A-Za-z0-9_./:\\-]+$/.test(text)) return text;
  return `"${text.replace(/"/g, '""')}"`;
}

function commandResult(command, args, cwd, env, stdio = 'pipe') {
  const options = {
    cwd,
    env,
    stdio,
    shell: false,
    encoding: stdio === 'pipe' ? 'utf8' : undefined,
  };
  if (process.platform === 'win32' && ['pnpm', 'corepack', 'pnpm.cmd', 'corepack.cmd'].includes(command.toLowerCase())) {
    const comspec = process.env.ComSpec || 'cmd.exe';
    const line = [command, ...args].map(windowsQuote).join(' ');
    return spawnSync(comspec, ['/d', '/s', '/c', line], options);
  }
  return spawnSync(command, args, options);
}

function gitOutput(root, args) {
  const result = spawnSync('git', args, { cwd: root, stdio: 'pipe', shell: false, encoding: 'utf8' });
  if (result.error || result.status !== 0) return null;
  return String(result.stdout || '').trim();
}

function gitHead(root) {
  return gitOutput(root, ['rev-parse', 'HEAD']);
}

function gitFileIsClean(root, relativePath) {
  const result = spawnSync('git', ['diff', '--quiet', '--', relativePath], { cwd: root, stdio: 'ignore', shell: false });
  const staged = spawnSync('git', ['diff', '--cached', '--quiet', '--', relativePath], { cwd: root, stdio: 'ignore', shell: false });
  return !result.error && result.status === 0 && !staged.error && staged.status === 0;
}

function markerCompatible(root, entry, head) {
  if (!head || !KNOWN_COMPATIBLE_GIT_HEADS.has(head)) return false;
  if (!gitFileIsClean(root, entry.path)) return false;
  const markers = COMPATIBILITY_MARKERS[entry.path];
  if (!markers) return true;
  const text = canonicalText(fileBuffer(root, entry.path));
  return markers.every((marker) => text.includes(marker));
}

function prevalidate(root) {
  const sharedPath = join(root, 'shared', 'src', 'index.ts');
  const sharedText = canonicalText(readFileSync(sharedPath));
  if (!sharedText.includes(REQUIRED_BASE_MARKER)) {
    throw new Error(`010D 기준 마커가 없습니다: ${REQUIRED_BASE_MARKER}`);
  }

  const head = gitHead(root);
  const normalizedMatches = [];
  const compatibleMatches = [];
  const alreadyMarked = sharedText.includes(PATCH_MARKER);

  if (alreadyMarked) {
    const mismatched = [];
    for (const entry of files) {
      const absolute = join(root, entry.path);
      if (!existsSync(absolute)) {
        mismatched.push(`${entry.path}: 결과 파일 없음`);
        continue;
      }
      const actualCanonical = fileCanonicalSha(root, entry.path);
      const expectedCanonical = entryAfterCanonicalSha(entry);
      if (actualCanonical !== expectedCanonical) {
        mismatched.push(`${entry.path}: 011 결과 불일치 (actual=${actualCanonical}, expected=${expectedCanonical}, format=${detectTextFormat(fileBuffer(root, entry.path))})`);
      }
    }
    if (mismatched.length === 0) return { alreadyApplied: true, normalizedMatches, compatibleMatches, head };
    throw new Error(`011 마커는 있으나 결과 파일이 일치하지 않습니다:\n- ${mismatched.join('\n- ')}`);
  }

  const errors = [];
  for (const entry of files) {
    const absolute = join(root, entry.path);
    if (entry.existedBefore) {
      if (!existsSync(absolute)) {
        errors.push(`${entry.path}: 기준 파일 없음`);
        continue;
      }
      const buffer = fileBuffer(root, entry.path);
      const raw = sha256(buffer);
      const normalized = canonicalSha(buffer);
      if (raw === entry.beforeSha256) continue;
      if (normalized === entry.beforeSha256) {
        normalizedMatches.push(`${entry.path} (${detectTextFormat(buffer)})`);
        continue;
      }
      if (markerCompatible(root, entry, head)) {
        compatibleMatches.push(`${entry.path} (git ${head.slice(0, 7)} clean baseline)`);
        continue;
      }
      errors.push(
        `${entry.path}: 010D 기준 불일치\n` +
        `  raw=${raw}\n` +
        `  normalized=${normalized}\n` +
        `  expected=${entry.beforeSha256}\n` +
        `  format=${detectTextFormat(buffer)}${head ? `\n  gitHead=${head}` : ''}`,
      );
    } else if (existsSync(absolute)) {
      const actualCanonical = fileCanonicalSha(root, entry.path);
      const expectedCanonical = entryAfterCanonicalSha(entry);
      if (actualCanonical !== expectedCanonical) {
        errors.push(`${entry.path}: 새 파일 경로에 다른 파일이 이미 존재`);
      }
    }
  }

  if (errors.length) {
    throw new Error(
      `패치 사전 검증 실패:\n- ${errors.join('\n- ')}\n\n` +
      '안전상 파일을 수정하지 않았습니다. 위 raw/normalized/gitHead 값을 함께 전달하면 기준 버전을 정확히 보정할 수 있습니다.',
    );
  }
  return { alreadyApplied: false, normalizedMatches, compatibleMatches, head };
}

function backup(root, backupDir) {
  mkdirSync(backupDir, { recursive: true });
  const originalState = new Map();
  const manifest = { patch: PATCH_MARKER, createdAt: new Date().toISOString(), gitHead: gitHead(root), files: [] };
  for (const entry of files) {
    const source = join(root, entry.path);
    const existed = existsSync(source);
    originalState.set(entry.path, existed);
    if (!existed) {
      manifest.files.push({ path: entry.path, existed: false });
      continue;
    }
    const destination = join(backupDir, entry.path);
    mkdirSync(dirname(destination), { recursive: true });
    copyFileSync(source, destination);
    manifest.files.push({
      path: entry.path,
      existed: true,
      sha256: fileSha(root, entry.path),
      canonicalSha256: fileCanonicalSha(root, entry.path),
      format: detectTextFormat(fileBuffer(root, entry.path)),
    });
  }
  writeFileSync(join(backupDir, 'manifest.json'), JSON.stringify(manifest, null, 2), 'utf8');
  return originalState;
}

function writePatchedFiles(root) {
  const written = [];
  try {
    for (const entry of files) {
      const absolute = join(root, entry.path);
      mkdirSync(dirname(absolute), { recursive: true });
      const temporary = `${absolute}.drop8-011-tmp`;
      writeFileSync(temporary, entryAfterBuffer(entry));
      copyFileSync(temporary, absolute);
      unlinkSync(temporary);
      if (process.platform !== 'win32' && entry.path.endsWith('.cmd')) chmodSync(absolute, 0o644);
      written.push(entry.path);
    }
  } catch (error) {
    for (const relativePath of written) {
      const temporary = `${join(root, relativePath)}.drop8-011-tmp`;
      if (existsSync(temporary)) rmSync(temporary, { force: true });
    }
    throw error;
  }

  const mismatched = files.filter((entry) => {
    const target = join(root, entry.path);
    return !existsSync(target) || fileSha(root, entry.path) !== entry.afterSha256;
  });
  if (mismatched.length) throw new Error(`패치 기록 검증 실패: ${mismatched.map((entry) => entry.path).join(', ')}`);
}

function rollback(root, backupDir, originalState) {
  for (const entry of files) {
    const destination = join(root, entry.path);
    const saved = join(backupDir, entry.path);
    if (originalState.get(entry.path)) {
      if (existsSync(saved)) {
        mkdirSync(dirname(destination), { recursive: true });
        copyFileSync(saved, destination);
      }
    } else if (existsSync(destination)) {
      rmSync(destination, { force: true });
    }
    const temporary = `${destination}.drop8-011-tmp`;
    if (existsSync(temporary)) rmSync(temporary, { force: true });
  }
}

function preparePnpmEnvironment(root) {
  const env = { ...process.env };
  const direct = commandResult('pnpm', ['--version'], root, env);
  if (!direct.error && direct.status === 0) {
    return { env, command: 'pnpm', cleanup: () => {}, mode: 'global pnpm' };
  }

  const corepack = commandResult('corepack', ['pnpm', '--version'], root, env);
  if (corepack.error || corepack.status !== 0) {
    const detail = String(corepack.stderr || direct.stderr || corepack.error?.message || direct.error?.message || '').trim();
    throw new Error(`pnpm 또는 Corepack pnpm을 실행할 수 없습니다.${detail ? `\n${detail}` : ''}`);
  }

  const shimDir = join(tmpdir(), `drop8-pnpm-shim-${process.pid}-${Date.now()}`);
  mkdirSync(shimDir, { recursive: true });
  if (process.platform === 'win32') {
    writeFileSync(join(shimDir, 'pnpm.cmd'), '@echo off\r\ncorepack pnpm %*\r\n', 'utf8');
  } else {
    const shimPath = join(shimDir, 'pnpm');
    writeFileSync(shimPath, '#!/usr/bin/env sh\nexec corepack pnpm "$@"\n', 'utf8');
    chmodSync(shimPath, 0o755);
  }
  env.PATH = `${shimDir}${process.platform === 'win32' ? ';' : ':'}${env.PATH || ''}`;
  return {
    env,
    command: 'pnpm',
    cleanup: () => rmSync(shimDir, { recursive: true, force: true }),
    mode: 'Corepack pnpm shim',
  };
}

function runValidation(root) {
  const setup = preparePnpmEnvironment(root);
  console.log(`\n[Refactor 011] 패키지 관리자: ${setup.mode}`);
  try {
    for (const task of ['typecheck', 'lint', 'test', 'build']) {
      console.log(`\n[Refactor 011] pnpm ${task}`);
      const result = commandResult(setup.command, [task], root, setup.env, 'inherit');
      if (result.error || result.status !== 0) {
        throw new Error(`자동 검증 실패: pnpm ${task}${result.error ? ` (${result.error.message})` : ''}`);
      }
    }
  } finally {
    setup.cleanup();
  }
}

const root = findProjectRoot();
console.log(`[Refactor 011] 프로젝트 루트: ${root}`);
const state = prevalidate(root);
if (state.normalizedMatches.length) {
  console.log(`[Refactor 011] Windows 줄바꿈/BOM 정규화 확인: ${state.normalizedMatches.join(', ')}`);
}
if (state.compatibleMatches.length) {
  console.log(`[Refactor 011] Git 010D 호환 기준 확인: ${state.compatibleMatches.join(', ')}`);
}
if (state.alreadyApplied) {
  console.log('[Refactor 011] 이미 동일한 패치가 적용되어 있습니다. 변경하지 않았습니다.');
  process.exit(0);
}
if (process.argv.includes('--dry-run')) {
  console.log(`[Refactor 011] 사전 검증 통과: ${files.length}개 파일 (파일 변경 없음)`);
  process.exit(0);
}

const backupDir = uniqueBackupDir(root);
const originalState = backup(root, backupDir);
console.log(`[Refactor 011] 백업 완료: ${backupDir}`);

try {
  writePatchedFiles(root);
  console.log(`[Refactor 011] ${files.length}개 파일 적용 및 해시 검증 완료`);
  runValidation(root);
  console.log('\n[Refactor 011] Sound Foundation & Combat Audio Pass 적용 완료');
  console.log(`[Refactor 011] 백업 유지: ${backupDir}`);
  console.log('[Refactor 011] LAN 실행: DROP8_LAN_START_011.cmd 더블클릭 또는 pnpm dev:lan');
} catch (error) {
  rollback(root, backupDir, originalState);
  console.error('\n[Refactor 011] 검사 또는 적용 실패로 011 변경 파일을 원본으로 자동 복원했습니다.');
  console.error(`[Refactor 011] 백업은 유지됩니다: ${backupDir}`);
  throw error;
}
